import { AgentRole, StructuredWorkflow } from "@aiagentflow/cli";

const workflow = new StructuredWorkflow({
  roles: [AgentRole.Architect, AgentRole.Coder, AgentRole.Reviewer],
  model: "claude-3-5-sonnet-20241022",
  rootDir: "./src"
});

await workflow.run("একটি ডাইনামিক প্রাইসিং টেবিল কম্পোনেন্ট তৈরি করুন");

